#include<stdio.h>
int main()
{
	long long int A,B,C,D,i;
	long long int res=0;
	scanf("%lld%lld%lld%lld",&A,&B,&C,&D);
	for(i=C;i<=D;i++)
	{
		if(i+2>=A+B)
			res+=((i-A-B+2)*(i-A-B+1))/2;
		if(i+2>=2*B+1)
			res-=((i-2*B+1)*(i-2*B))/2;
		if(i+2>=A+C+1)
			res-=((i-A-C+1)*(i-A-C))/2;
		if(i-B-C>=0)
			res+=((i-B-C)*(i-B-C-1))/2;
	}
	res=(B-A+1)*(C-B+1)*(D-C+1)-res;
	printf("%lld\n",res);
}

