#![allow(unused_imports)]
#![allow(non_snake_case)]
use std::cmp::*;
use std::collections::*;
use std::io::Write;

#[allow(unused_macros)]
macro_rules! debug {
    ($($e:expr),*) => {
        #[cfg(debug_assertions)]
        $({
            let (e, mut err) = (stringify!($e), std::io::stderr());
            writeln!(err, "{} = {:?}", e, $e).unwrap()
        })*
    };
}

fn main() {
    let v = read_vec::<usize>();
    let (a, b, c, d) = (v[0], v[1], v[2], v[3]);

    let mut count = vec![0i64; b + c + 2];
    for x in a..b + 1 {
        count[x + b] += 1;
        count[x + c + 1] -= 1;
    }
    let mut accum = vec![0i64; b + c + 2];
    accum[0] = count[0];
    for x in 1..b + c + 1 {
        accum[x] = accum[x - 1] + count[x];
    }

    let mut ans = 0i64;
    for x_p_y in 1..b + c + 1 {
        let z_max = min(x_p_y - 1, d) as i64;
        let z_min = c as i64;
        ans += accum[x_p_y] * max(z_max - z_min + 1, 0);
    }
    println!("{}", ans);
}

fn read<T: std::str::FromStr>() -> T {
    let mut s = String::new();
    std::io::stdin().read_line(&mut s).ok();
    s.trim().parse().ok().unwrap()
}

fn read_vec<T: std::str::FromStr>() -> Vec<T> {
    read::<String>()
        .split_whitespace()
        .map(|e| e.parse().ok().unwrap())
        .collect()
}
